// Gather market signals per supplier/country. FREE sources (news RSS + FX) always run.
// X / LinkedIn run via APIFY actors only if APIFY_TOKEN is set — otherwise skipped at zero cost.
const targets = [
  { supplier: 'Brazil beef suppliers', commodity: 'beef', country: 'Brazil', cur: 'BRL', q: 'Brazil beef export OR cattle price OR meatpacking' },
  { supplier: 'India buffalo meat', commodity: 'beef', country: 'India', cur: 'INR', q: 'India buffalo meat export price OR ban' },
  { supplier: 'Brazil chicken', commodity: 'chicken', country: 'Brazil', cur: 'BRL', q: 'Brazil chicken poultry export avian flu price' },
  { supplier: 'Egypt potatoes', commodity: 'potato', country: 'Egypt', cur: 'EGP', q: 'Egypt potato export price OR weather OR crop' },
  { supplier: 'KSA import logistics', commodity: 'all', country: 'Saudi Arabia', cur: 'USD', q: 'Saudi Arabia port Jeddah Dammam shipping delay customs food import' }
];
function parseRss(xml, n) {
  const items = []; const re = /<item>([\s\S]*?)<\/item>/g; let m;
  const pick = (s, t) => { const r = new RegExp('<' + t + '>([\\s\\S]*?)<\\/' + t + '>').exec(s); return r ? r[1].replace(/<!\[CDATA\[|\]\]>/g, '').replace(/<[^>]+>/g, '').trim() : ''; };
  while ((m = re.exec(xml)) && items.length < n) { const b = m[1]; items.push({ title: pick(b, 'title'), url: pick(b, 'link'), source: pick(b, 'source') || 'News', date: pick(b, 'pubDate') }); }
  return items;
}
const apify = $env.APIFY_TOKEN;
const xActor = $env.APIFY_TWITTER_ACTOR || 'apidojo~tweet-scraper';
const liActor = $env.APIFY_LINKEDIN_ACTOR;
async function apifyRun(actor, input, map) {
  if (!apify || !actor) return [];
  try {
    const items = await this.helpers.httpRequest({ method: 'POST', url: `https://api.apify.com/v2/acts/${actor}/run-sync-get-dataset-items?token=${apify}`, body: input, json: true, timeout: 90000 });
    return (Array.isArray(items) ? items : []).slice(0, 5).map(map).filter(s => s.title);
  } catch (e) { return []; }
}
const out = [];
for (const t of targets) {
  let articles = [];
  const feeds = [
    `https://news.google.com/rss/search?q=${encodeURIComponent(t.q)}+when:3d&hl=en-US&gl=US&ceid=US:en`,
    `https://www.bing.com/news/search?q=${encodeURIComponent(t.q)}&format=rss`
  ];
  for (const url of feeds) { try { const xml = await this.helpers.httpRequest({ url, json: false, timeout: 15000 }); articles = articles.concat(parseRss(String(xml), 5)); } catch (e) {} }
  let fx = null;
  try { const r = await this.helpers.httpRequest({ url: `https://open.er-api.com/v6/latest/${t.cur}`, json: true, timeout: 15000 }); if (r && r.rates && r.rates.SAR) fx = { pair: `${t.cur}/SAR`, rate: r.rates.SAR, asOf: r.time_last_update_utc || '' }; } catch (e) {}
  let social = [];
  social = social.concat(await apifyRun.call(this, xActor, { searchTerms: [t.q], maxItems: 5, sort: 'Latest' }, x => ({ title: x.text || x.full_text || x.content || '', url: x.url || x.twitterUrl || '', source: 'X', date: x.createdAt || x.created_at || '' })));
  social = social.concat(await apifyRun.call(this, liActor, { searchQuery: t.q, maxItems: 5 }, x => ({ title: x.text || x.content || x.summary || '', url: x.url || x.postUrl || '', source: 'LinkedIn', date: x.date || x.postedAt || '' })));
  out.push({ json: { supplier: t.supplier, commodity: t.commodity, country: t.country, fx, articles, social } });
}
return out;

