// Parse each model JSON; drop risks/drivers without a real citation (accuracy guard).
const out = [];
for (const item of $input.all()) {
  let o;
  try { o = JSON.parse(item.json.choices[0].message.content); } catch (e) { continue; }
  o.risks = (o.risks || []).filter(r => r && r.citation && r.citation.url && r.citation.source);
  if (o.price_outlook) o.price_outlook.drivers = (o.price_outlook.drivers || []).filter(d => d && d.citation && d.citation.url && d.citation.source);
  o.generated_at = $now.toISO();
  out.push({ json: o });
}
return out;
